# test_palindrome.py
import pytest

from your_module import is_palindrome  # Replace "your_module" with the actual module name


@pytest.mark.parametrize(
    "value, expected",
    [
        ("racecar", True),
        ("RaceCar", True),
        ("nurses run", True),
        ("Was it a car or a cat I saw", True),
        ("hello", False),
        ("palindrome", False),
        ("ab", False),
    ],
)
def test_is_palindrome_happy_path(value, expected):
    assert is_palindrome(value) is expected


@pytest.mark.parametrize(
    "value, expected",
    [
        ("", True),
        (" ", True),
        ("     ", True),
        ("a", True),
        ("A", True),
        ("aa", True),
        ("Aa", True),
    ],
)
def test_is_palindrome_edge_cases(value, expected):
    assert is_palindrome(value) is expected


def test_is_palindrome_ignores_spaces_only():
    assert is_palindrome("a b a") is True


def test_is_palindrome_does_not_ignore_punctuation():
    assert is_palindrome("Madam, I'm Adam") is False


def test_is_palindrome_does_not_ignore_tabs():
    assert is_palindrome("a\tba") is False


@pytest.mark.parametrize("value", [None, 123, ["racecar"]])
def test_is_palindrome_invalid_types_raise_attribute_error(value):
    with pytest.raises(AttributeError):
        is_palindrome(value)


def test_is_palindrome_bytes_raise_type_error():
    with pytest.raises(TypeError):
        is_palindrome(b"racecar")
